import { ApiService, User, UserResponse } from '@stitchwill/api';
import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { LoginUser, LoginUserRequest, NewUserRequest, NewUser } from './auth.interfaces';

export interface Token {
  authToken: string;
}
@Injectable()
export class AuthService {
  constructor(private apiService: ApiService) {}

  user(authToken: string): Observable<boolean> {
    return this.apiService.post<boolean, Token>('Login/Auth', { authToken: authToken } );
  }

  login(credentials: LoginUser): Observable<User> {
    return this.apiService.post<User, LoginUser>('Login/LoginRequest', credentials );
  }

  register(credentials: NewUser): Observable<UserResponse> {
    return this.apiService.post<UserResponse, NewUserRequest>('/users', { user: credentials });
  }
}
