import { BrowserModule } from '@angular/platform-browser';
import { NgModule } from '@angular/core';
import { ApiModule } from '@stitchwill/api';
import { AuthGuardService, AuthModule } from '@stitchwill/auth';
import { NgrxErrorModule } from '@stitchwill/ngrx-error';
import { NgrxRouterModule } from '@stitchwill/ngrx-router';
import { AppComponent } from './app.component';
import { NxModule } from '@nrwl/angular';
import { RouterModule } from '@angular/router';
import { environment } from '../environments/environment';

import { EffectsModule } from '@ngrx/effects';
import { StoreModule } from '@ngrx/store';
import { StoreDevtoolsModule } from '@ngrx/store-devtools';
import { from } from 'rxjs';
import { HeaderComponent } from './layout/header/header.component';
import { FooterComponent } from './layout/footer/footer.component';


@NgModule({
  declarations: [AppComponent, HeaderComponent, FooterComponent],
  imports: [
    ApiModule,
    AuthModule,
    BrowserModule,
    NxModule.forRoot(),
    RouterModule.forRoot(
      [
        {
          path: '',
          loadChildren: () =>
            import('@stitchwill/home').then((m) => m.HomeModule),
        },
        {
          path: 'home',
          loadChildren: () =>
            import('@stitchwill/home').then((m) => m.HomeModule),
        },
        {
          path: 'profile',
          loadChildren: () =>
            import('@stitchwill/profile').then((m) => m.ProfileModule),
          canActivate: [AuthGuardService]
        },
        {
          path: 'menu',
          loadChildren: () =>
            import('@stitchwill/menu').then((m) => m.MenuModule),
        },
        {
          path: 'search',
          loadChildren: () =>
            import('@stitchwill/search').then((m) => m.SearchModule),
        },
        {
          path: 'product',
          loadChildren: () =>
            import('@stitchwill/product').then((m) => m.ProductModule),
        },
      ],
      {
        initialNavigation: 'enabled',
        useHash: true,
        relativeLinkResolution: 'legacy',
      },
    ),
    StoreModule.forRoot({}),
    EffectsModule.forRoot([]),
    !environment.production ? StoreDevtoolsModule.instrument() : [],
    NgrxRouterModule,
    NgrxErrorModule,
  ],
  providers: [],
  bootstrap: [AppComponent],
})
export class AppModule {}
